using Microsoft.AspNetCore.Diagnostics.HealthChecks;using Portal.BuildingBlocks;using Portal.Notification.Infrastructure;using Portal.Notification.Worker;
var b=WebApplication.CreateBuilder(args);b.AddPortalFoundation("Portal.Notification.Worker");b.Services.AddNotificationFoundation(b.Configuration);b.Services.Configure<NotificationWorkerOptions>(b.Configuration.GetSection("Worker"));b.Services.AddHostedService<NotificationBackgroundWorker>();b.Services.AddHealthChecks().AddDbContextCheck<NotificationDbContext>();var app=b.Build();app.UsePortalFoundation();app.MapHealthChecks("/health",new HealthCheckOptions());app.Run();
